# scripts/notify_release.py
# Send release notes to Slack when a new version is tagged.
import sys, json, urllib.request, os

SLACK_WEBHOOK = os.environ["SLACK_WEBHOOK_URL"]

def send_slack_notification(version: str, operator_notes: str) -> None:
    # Format as a Slack message with sections
    blocks = [
        {
            "type": "header",
            "text": {"type": "plain_text", "text": f"GenAI Service Release: {version}"}
        },
        {
            "type": "section",
            "text": {
                "type": "mrkdwn",
                "text": operator_notes[:2900]   # Slack block limit
            }
        },
        {
            "type": "actions",
            "elements": [
                {
                    "type": "button",
                    "text": {"type": "plain_text", "text": "View Full Changelog"},
                    "url": f"https://github.com/my-org/genai-api/releases/tag/{version}"
                }
            ]
        }
    ]

    payload = json.dumps({"blocks": blocks}).encode()
    req = urllib.request.Request(
        SLACK_WEBHOOK,
        data=payload,
        headers={"Content-Type": "application/json"},
        method="POST"
    )
    with urllib.request.urlopen(req) as resp:
        if resp.status != 200:
            raise RuntimeError(f"Slack notification failed: {resp.status}")
    print(f"Slack notification sent for {version}")

if __name__ == "__main__":
    version = sys.argv[1]
    notes = sys.stdin.read()
    send_slack_notification(version, notes)

# scripts/generate_changelog_json.py
import json, sys
from generate_changelog import git_commits, CommitEntry

def to_json_changelog(entries: list[CommitEntry], version: str, date: str) -> dict:
    return {
        "version": version,
        "date": date,
        "commits": [
            {
                "sha": e.sha,
                "type": e.commit_type,
                "scope": e.scope,
                "description": e.description,
                "is_breaking": e.is_breaking,
                "eval_cases": e.eval_cases,
                "refs": e.refs,
            }
            for e in entries
        ],
        "stats": {
            "total": len(entries),
            "breaking": sum(1 for e in entries if e.is_breaking),
            "by_type": {
                t: sum(1 for e in entries if e.commit_type == t)
                for t in set(e.commit_type for e in entries)
            },
            "eval_cases_added": list({
                c for e in entries if e.commit_type == "eval"
                for c in e.eval_cases
            }),
        }
    }

if __name__ == "__main__":
    since = sys.argv[1] if len(sys.argv) > 1 else "v1.0.0"
    version = sys.argv[2] if len(sys.argv) > 2 else "NEXT"
    date = sys.argv[3] if len(sys.argv) > 3 else "2024-01-15"
    entries = git_commits(since)
    print(json.dumps(to_json_changelog(entries, version, date), indent=2))
